Real64 CalcPipeTransBeam(Real64 const R,    // Reflectance of surface, constant (can be made R = f(theta) later)
                             Real64 const A,    // Aspect ratio, L / d
                             Real64 const Theta // Angle of entry in radians
    )
    {

        // SUBROUTINE INFORMATION:
        //       AUTHOR         Peter Graham Ellis
        //       DATE WRITTEN   May 2003
        //       MODIFIED       na
        //       RE-ENGINEERED  na

        // PURPOSE OF THIS SUBROUTINE:
        // Calculates the numerical integral for the transmittance of a reflective cylinder with
        // incident collimated beam radiation as described in Swift and Smith.

        // METHODOLOGY EMPLOYED:
        // Since this integral can be slow, a table of values is calculated and stored during
        // initialization of the TDD.  Intermediate values are calculated by interpolation.
        // Transmittance of sky and ground diffuse radiation is done by other functions.

        // REFERENCES:
        // Swift, P. D., and Smith, G. B.  "Cylindrical Mirror Light Pipes",
        //   Solar Energy Materials and Solar Cells 36 (1995), pp. 159-168.

        // OTHER NOTES:
        // The execution time of this function can be reduced by adjusting parameters N and xTol below.
        // However, there is some penalty in accuracy for N < 100,000 and xTol > 150.

        // USE STATEMENTS: na

        // Return value
        Real64 CalcPipeTransBeam;

        // Locals
        // FUNCTION ARGUMENT DEFINITIONS:

        // FUNCTION PARAMETER DEFINITIONS:
        Real64 constexpr N(100000.0); // Number of integration points
        Real64 constexpr xTol(150.0); // Tolerance factor to skip iterations where dT is approximately 0
        // Must be >= 1.0, increase this number to decrease the execution time
        Real64 const myLocalTiny(TINY(1.0));

        // FUNCTION LOCAL VARIABLE DECLARATIONS:
        Real64 i; // Integration interval between points
        Real64 s; // Entry point
        Real64 dT;
        Real64 T; // Beam transmittance for collimated solar real
        Real64 x; // Intermediate variables for speed optimization
        Real64 c1;
        Real64 c2;
        Real64 xLimit; // Limiting x value to prevent floating point underflow

        CalcPipeTransBeam = 0.0;

        T = 0.0;
        i = 1.0 / N;

        xLimit = (std::log(pow_2(N) * myLocalTiny) / std::log(R)) / xTol;

        c1 = A * std::tan(Theta);
        c2 = 4.0 / Constant::Pi;

        s = i;
        while (s < (1.0 - i)) {
            x = c1 / s;

            if (x < xLimit) {
                dT = c2 * std::pow(R, int(x)) * (1.0 - (1.0 - R) * (x - int(x))) * pow_2(s) / std::sqrt(1.0 - pow_2(s));
                T += dT;
            }

            s += i;
        }

        T /= (N - 1.0); // - 1.0, because started on i, not 0

        CalcPipeTransBeam = T;

        return CalcPipeTransBeam;
    }

Real64 DayltgGlarePositionFactor(Real64 X, // Lateral and vertical distance of luminous window element from
                                 Real64 Y)
{

    // SUBROUTINE INFORMATION:
    //       AUTHOR         Fred Winkelmann
    //       DATE WRITTEN   July 1997

    // PURPOSE OF THIS SUBROUTINE:
    // by table interpolation, evaluates the
    // Hopkinson position factor used in glare calculation
    // (Hopkinson, Petherbridge, AND Longmore -- Daylighting,
    // London, 1966, PP 307, 323).  X (Y) is the lateral
    // (vertical) distance of luminous window element from
    // horizontal line of vision, divided by horizontal distance
    // from eye of observer. The array PF contains values of
    // the position factor for X = 0, 0.5, 1.0, 1.5, 2.0, 2.5,
    // and 3.0 and Y = 0, 0.5, 1.0, 1.5, 2.0. Called by CalcDayltgCoefficients.

    // REFERENCES:
    // Based on DOE-2.1E subroutine DPFAC.

    // Position factor array
    static constexpr std::array<std::array<Real64, 7>, 5> PF = {{
        {1.00, 0.492, 0.226, 0.128, 0.081, 0.061, 0.057},
        {0.123, 0.119, 0.065, 0.043, 0.029, 0.026, 0.023},
        {0.019, 0.026, 0.019, 0.016, 0.014, 0.011, 0.011},
        {0.008, 0.008, 0.008, 0.008, 0.008, 0.006, 0.006},
        {0.0, 0.0, 0.003, 0.003, 0.003, 0.003, 0.003},
    }};

    if (X < 0.0 || X >= 3.0) {
        return 0.0;
    }
    if (Y < 0.0 || Y >= 2.0) {
        return 0.0;
    }

    int IX = 1 + int(2.0 * X);
    int IY = 1 + int(2.0 * Y);
    Real64 X1 = 0.5 * double(IX - 1);
    Real64 Y1 = 0.5 * double(IY - 1);
    Real64 FA = PF[IY - 1][IX - 1] + 2.0 * (X - X1) * (PF[IY - 1][IX] - PF[IY - 1][IX - 1]);
    Real64 FB = PF[IY][IX - 1] + 2.0 * (X - X1) * (PF[IY][IX] - PF[IY][IX - 1]);
    return FA + 2.0 * (Y - Y1) * (FB - FA);
}

Real64 pvstar(Real64 const T)
    {
        // Thermodynamic parameters
        constexpr Real64 Ttrip = 273.16; // K
        constexpr Real64 ptrip = 611.65; // Pa
        constexpr Real64 E0v = 2.3740e6; // J/kg
        constexpr Real64 E0s = 0.3337e6; // J/kg
        // constexpr Real64 rgasa = 287.04; // J/kg/K
        constexpr Real64 rgasv = 461.; // J/kg/K
        // constexpr Real64 cva = 719.;     // J/kg/K
        constexpr Real64 cvv = 1418.; // J/kg/K
        constexpr Real64 cvl = 4119.; // J/kg/K
        constexpr Real64 cvs = 1861.; // J/kg/K
        // constexpr Real64 cpa = cva + rgasa;
        constexpr Real64 cpv = cvv + rgasv;

        if (T == 0.0) {
            return 0.0;
